INSERT INTO articulos (etapa, categoria, titulo, resumen, contenido, destacado, orden) VALUES
('0-1', 'lavado', '¿Cuándo empezar a limpiar la boca de tu bebé?', 'Desde el primer día de vida, la higiene bucal ya es importante. Antes de que salgan los dientes, puedes limpiar las encías con una gasa húmeda o un de...', 'Desde el primer día de vida, la higiene bucal ya es importante. Antes de que salgan los dientes, puedes limpiar las encías con una gasa húmeda o un dedal de silicona. Cuando aparezca el primer diente (normalmente entre los 6 y 12 meses), empieza a usar un cepillo de dientes infantil con una mínima cantidad de pasta fluorada, del tamaño de un grano de arroz.', true, 1),
('0-1', 'lavado', 'El primer cepillo: ¿qué debo buscar?', 'Para los bebés, el cepillo ideal tiene cabezal muy pequeño, cerdas ultrasuaves y mango grueso para que el adulto lo sostenga con facilidad. No hace fa...', 'Para los bebés, el cepillo ideal tiene cabezal muy pequeño, cerdas ultrasuaves y mango grueso para que el adulto lo sostenga con facilidad. No hace falta mojarlo; solo una pizca de pasta fluorada (1.000 ppm) es suficiente. Cepilla con movimientos suaves desde que sale cada diente. Cambia el cepillo cada 3 meses o antes si las cerdas se doblan.', false, 2),
('0-1', 'lavado', '¿Pasta de dientes en bebés? Sí, desde el primer diente', 'Muchos padres dudan sobre usar pasta fluorada en bebés, pero las guías pediátricas actuales la recomiendan desde la erupción del primer diente. La cla...', 'Muchos padres dudan sobre usar pasta fluorada en bebés, pero las guías pediátricas actuales la recomiendan desde la erupción del primer diente. La clave está en la cantidad: un toque del tamaño de un grano de arroz es seguro. El flúor fortalece el esmalte y protege contra las caries desde muy temprano. Si el bebé traga un poco, esa cantidad mínima no es perjudicial.', false, 3),
('0-1', 'lavado', 'Rutina nocturna: el cepillado más importante del día', 'El cepillado antes de dormir es el más importante porque, durante la noche, la producción de saliva disminuye y los dientes quedan más expuestos a los...', 'El cepillado antes de dormir es el más importante porque, durante la noche, la producción de saliva disminuye y los dientes quedan más expuestos a los ácidos. Después del último biberón o toma, limpia siempre los dientes del bebé. Evita que se duerma con el biberón en la boca: el azúcar de la leche en contacto prolongado con los dientes puede causar caries temprana de la infancia.', false, 4),
('0-1', 'alimentacion', 'La leche materna y el biberón: su efecto en los dientes', 'La leche materna es el alimento ideal para los bebés, pero en contacto prolongado con los dientes puede favorecer las caries, especialmente si el bebé...', 'La leche materna es el alimento ideal para los bebés, pero en contacto prolongado con los dientes puede favorecer las caries, especialmente si el bebé se duerme durante la toma. Lo mismo ocurre con el biberón. La solución no es dejar de amamantar, sino limpiar siempre los dientes después de la última toma del día. Evita los biberones con jugos o líquidos azucarados, que son mucho más perjudiciales.', false, 5),
('0-1', 'alimentacion', 'Azúcar oculto en los primeros alimentos', 'Cuando introduces la alimentación complementaria (a partir de los 6 meses), presta atención al azúcar. Muchos purés y papillas comerciales contienen a...', 'Cuando introduces la alimentación complementaria (a partir de los 6 meses), presta atención al azúcar. Muchos purés y papillas comerciales contienen azúcares añadidos. Lee siempre las etiquetas. Los jugos de frutas, aunque naturales, también son ácidos y dulces: no son recomendables antes del año. Opta por fruta entera o en puré sin añadidos. Un inicio sin azúcar sienta las bases de una boca sana.', false, 6),
('0-1', 'alimentacion', 'Chupete: ¿Amigo o enemigo de los dientes?', 'El chupete puede ser útil para calmar al bebé y reduce el riesgo de muerte súbita. Sin embargo, mojarlo en miel, azúcar o mermelada es un hábito muy p...', 'El chupete puede ser útil para calmar al bebé y reduce el riesgo de muerte súbita. Sin embargo, mojarlo en miel, azúcar o mermelada es un hábito muy perjudicial que puede causar caries graves. Usa siempre el chupete limpio y sin edulcorantes. Si el bebé ha empezado a tener dientes, habla con el dentista sobre cuándo es buen momento para ir retirando su uso gradualmente.', false, 7),
('0-1', 'alimentacion', 'Agua: el mejor complemento para la salud bucal', 'Desde los 6 meses, puedes ofrecer pequeñas cantidades de agua a tu bebé, especialmente después de las comidas. El agua ayuda a limpiar la boca y neutr...', 'Desde los 6 meses, puedes ofrecer pequeñas cantidades de agua a tu bebé, especialmente después de las comidas. El agua ayuda a limpiar la boca y neutraliza los ácidos. Si en tu zona el agua del grifo contiene flúor en niveles adecuados, aún mejor. Evita los zumos, infusiones azucaradas o bebidas con sabor antes del año: acostumbran al bebé al sabor dulce y dañan el esmalte dental.', false, 8),
('0-1', 'dentista', '¿Cuándo llevar al bebé al dentista por primera vez?', 'La recomendación internacional es acudir al dentista cuando aparezca el primer diente o, como máximo, antes de cumplir el año. Esta primera visita no ...', 'La recomendación internacional es acudir al dentista cuando aparezca el primer diente o, como máximo, antes de cumplir el año. Esta primera visita no es un tratamiento: es una revisión preventiva donde el profesional evalúa el desarrollo bucal, la higiene, la lactancia y posibles riesgos de caries. También es una oportunidad para que los padres reciban orientación personalizada. Cuanto antes, mejor.', false, 9),
('0-1', 'dentista', '¿De qué habla el dentista en la primera visita?', 'En la primera consulta, el dentista observa las encías, los dientes que han erupcionado, el frenillo y el paladar del bebé. Valora hábitos como el chu...', 'En la primera consulta, el dentista observa las encías, los dientes que han erupcionado, el frenillo y el paladar del bebé. Valora hábitos como el chupete o el biberón nocturno. Los padres pueden preguntar sobre higiene, alimentación y signos de alarma. No hay nada invasivo: es una visita tranquila, corta y muy informativa que sienta las bases de una relación positiva con el dentista desde pequeño.', false, 10),
('0-1', 'dentista', 'Signos de alarma que no debes ignorar', 'Consulta al dentista si notas manchas blancas o marrones en los dientes del bebé (pueden ser caries), encías muy hinchadas o sangrantes sin motivo apa...', 'Consulta al dentista si notas manchas blancas o marrones en los dientes del bebé (pueden ser caries), encías muy hinchadas o sangrantes sin motivo aparente, retraso en la aparición de los primeros dientes (más allá de los 12-14 meses) o un frenillo que parezca limitar el movimiento de la lengua y dificulte la lactancia. La detección temprana permite actuar antes de que el problema avance.', false, 11),
('0-1', 'dentista', 'Cómo hacer que la visita al dentista sea algo positivo', 'La actitud de los padres influye mucho en cómo vive el bebé la visita. Habla de ella con naturalidad, sin usar palabras como ''dolor'' o ''no te va a hac...', 'La actitud de los padres influye mucho en cómo vive el bebé la visita. Habla de ella con naturalidad, sin usar palabras como ''dolor'' o ''no te va a hacer nada''. Lleva al bebé bien descansado y sin hambre. Muchas clínicas pediátricas están especialmente diseñadas para que el ambiente sea amigable. Una buena primera experiencia es la mejor inversión para que tu hijo crezca sin miedo al dentista.', false, 12),
('0-1', 'salud', 'La dentición: lo que es normal y lo que no', 'La salida de los primeros dientes suele empezar entre los 6 y los 10 meses. Es normal que el bebé babee más, esté irritable y quiera morder todo. Lo q...', 'La salida de los primeros dientes suele empezar entre los 6 y los 10 meses. Es normal que el bebé babee más, esté irritable y quiera morder todo. Lo que NO es normal es la fiebre alta (más de 38°C) ni la diarrea, síntomas que no están causados por la dentición y requieren visita al pediatra. Para aliviar las molestias, ofrece mordedores fríos (no congelados) o masajea suavemente las encías con el dedo limpio.', false, 13),
('0-1', 'salud', 'Caries de la infancia temprana: cómo prevenirla', 'La caries en bebés existe y es más común de lo que se piensa. Se llama ''caries de biberón'' y aparece cuando los dientes están expuestos de forma prolo...', 'La caries en bebés existe y es más común de lo que se piensa. Se llama ''caries de biberón'' y aparece cuando los dientes están expuestos de forma prolongada a líquidos dulces, especialmente por las noches. Los primeros signos son manchas blancas opacas en los dientes frontales superiores. La prevención es sencilla: no des biberón por la noche (o límpialo después), no mojes el chupete en azúcar y realiza higiene bucal diaria.', false, 14),
('0-1', 'salud', 'El flúor en bebés: mitos y realidades', 'El flúor es seguro y beneficioso cuando se usa correctamente. En bebés, la fuente principal es la pasta dental fluorada en cantidad de grano de arroz....', 'El flúor es seguro y beneficioso cuando se usa correctamente. En bebés, la fuente principal es la pasta dental fluorada en cantidad de grano de arroz. No necesitan suplementos de flúor salvo indicación médica específica. El flúor fortalece el esmalte y reduce el riesgo de caries hasta en un 25%. La fluorosis (manchas por exceso de flúor) solo ocurre si se ingieren cantidades muy superiores a las recomendadas, algo poco probable con el uso correcto.', false, 15),
('0-1', 'salud', 'El orden de salida de los dientes de leche', 'Los dientes de leche siguen un orden bastante predecible: primero salen los incisivos centrales inferiores (6-10 meses), luego los superiores (8-12 me...', 'Los dientes de leche siguen un orden bastante predecible: primero salen los incisivos centrales inferiores (6-10 meses), luego los superiores (8-12 meses), después los laterales, los primeros molares, los caninos y finalmente los segundos molares, completando la dentición a los 2-3 años. Conocer este orden te ayuda a entender el desarrollo de tu bebé y detectar variaciones que valga la pena comentar con el dentista.', false, 16),
('0-1', 'ortodoncia', '¿Puede un bebé necesitar ortodoncia?', 'En los bebés no se coloca ortodoncia en el sentido tradicional, pero sí existe una especialidad llamada ortopedia maxilofacial que actúa muy temprano ...', 'En los bebés no se coloca ortodoncia en el sentido tradicional, pero sí existe una especialidad llamada ortopedia maxilofacial que actúa muy temprano cuando hay alteraciones en el desarrollo de los maxilares. Algunos hábitos como el uso prolongado del chupete o la succión del dedo pueden influir en el desarrollo de la mordida. El dentista puede detectar en estas primeras visitas si existe algún riesgo que convenga monitorizar.', false, 17),
('0-1', 'ortodoncia', 'El frenillo lingual: cómo afecta a la boca del bebé', 'El frenillo lingual es el tejido que une la lengua al suelo de la boca. Cuando es corto o grueso (anquiloglosia), puede dificultar la lactancia y, más...', 'El frenillo lingual es el tejido que une la lengua al suelo de la boca. Cuando es corto o grueso (anquiloglosia), puede dificultar la lactancia y, más adelante, el habla. El dentista o el pediatra pueden detectarlo en los primeros días de vida. Si interfiere con la alimentación, existe un procedimiento sencillo llamado frenectomía para liberarlo. Su tratamiento temprano evita problemas de desarrollo bucal y del lenguaje.', false, 18),
('0-1', 'ortodoncia', 'Chupete y dedo: ¿cuándo empiezan a afectar a los dientes?', 'Hasta los 2 años, el uso del chupete y la succión del dedo son hábitos normales y no suelen causar problemas permanentes, ya que la dentición de leche...', 'Hasta los 2 años, el uso del chupete y la succión del dedo son hábitos normales y no suelen causar problemas permanentes, ya que la dentición de leche todavía está en desarrollo. Sin embargo, si estos hábitos continúan más allá de los 3-4 años, pueden comenzar a modificar la posición de los dientes y el desarrollo del paladar. Por eso, entre los 12 y 18 meses es un buen momento para empezar a planificar la retirada gradual del chupete.', false, 19),
('0-1', 'ortodoncia', 'Señales tempranas que el dentista vigila en bebés', 'En la primera visita, el dentista no solo mira los dientes: también evalúa el desarrollo de los maxilares, la posición de la lengua en reposo, la resp...', 'En la primera visita, el dentista no solo mira los dientes: también evalúa el desarrollo de los maxilares, la posición de la lengua en reposo, la respiración (nasal vs. bucal) y la simetría de la cara. Una respiración bucal habitual puede ser señal de obstrucción nasal e influir negativamente en el desarrollo facial. Detectar estos factores antes del año permite actuar de forma preventiva y evitar tratamientos más complejos en el futuro.', false, 20),
('2-6', 'lavado', 'Cepillado a los 2-6 años: técnica, tiempo y supervisión', 'A esta edad, los niños quieren cepillarse solos, pero aún no tienen la coordinación manual necesaria. Deja que lo intenten, pero siempre termina tú el...', 'A esta edad, los niños quieren cepillarse solos, pero aún no tienen la coordinación manual necesaria. Deja que lo intenten, pero siempre termina tú el cepillado. El tiempo recomendado es de 2 minutos, dos veces al día (mañana y noche). Usa una pasta con flúor de 1.000 ppm y el tamaño de un guisante. Enseña movimientos circulares suaves, cepillando todas las superficies: exterior, interior y masticatoria.', true, 1),
('2-6', 'lavado', 'Cómo hacer el cepillado divertido (sin batallas)', 'Convertir el cepillado en un juego es la clave para que los niños lo acepten de buen grado. Usa un temporizador o una canción de 2 minutos, deja que e...', 'Convertir el cepillado en un juego es la clave para que los niños lo acepten de buen grado. Usa un temporizador o una canción de 2 minutos, deja que el niño elija su cepillo con su personaje favorito, cepillaos juntos para que imite, o usa aplicaciones móviles de cepillado infantil con animaciones. Elogia y celebra cada cepillado bien hecho. Los premios simbólicos (pegatinas, un dibujo en la nevera) funcionan muy bien a esta edad.', false, 2),
('2-6', 'lavado', '¿Cuándo empezar a usar el hilo dental?', 'El hilo dental debe usarse en cuanto dos dientes estén en contacto el uno con el otro, lo que suele ocurrir entre los 2 y 3 años. El espacio entre die...', 'El hilo dental debe usarse en cuanto dos dientes estén en contacto el uno con el otro, lo que suele ocurrir entre los 2 y 3 años. El espacio entre dientes es donde más se acumula la placa y donde el cepillo no llega. Usa hilo dental específico para niños o palillos de hilo con mango para mayor facilidad. Al principio, los padres deben hacerlo; hacia los 6-8 años el niño puede empezar a aprender solo.', false, 3),
('2-6', 'lavado', 'El enjuague bucal: ¿a partir de qué edad?', 'Los enjuagues bucales con flúor no están recomendados antes de los 6 años, ya que los niños pueden tragarlos involuntariamente. La higiene a esta edad...', 'Los enjuagues bucales con flúor no están recomendados antes de los 6 años, ya que los niños pueden tragarlos involuntariamente. La higiene a esta edad se basa en un buen cepillado con pasta fluorada y el uso del hilo dental. Si el dentista lo considera necesario, puede recomendar un enjuague específico a partir de los 6 años. Nunca uses enjuagues con alcohol para niños. La clave es una buena técnica de cepillado, no añadir más productos.', false, 4),
('2-6', 'alimentacion', 'Los peores enemigos de los dientes en la mochila escolar', 'Muchos snacks aparentemente saludables son muy perjudiciales para los dientes: fruta desecada, barritas de cereales, galletas, zumos de fruta embotell...', 'Muchos snacks aparentemente saludables son muy perjudiciales para los dientes: fruta desecada, barritas de cereales, galletas, zumos de fruta embotellados y bebidas con sabor. Todos comparten una característica: azúcares que se adhieren al esmalte o que mantienen un pH ácido en la boca. Para el almuerzo escolar, opta por fruta fresca, queso, verduras crudas y agua. Reduce la frecuencia de exposición al azúcar, que es tan importante como la cantidad total.', false, 5),
('2-6', 'alimentacion', 'La frecuencia importa más que la cantidad de azúcar', 'No es lo mismo tomar un dulce de golpe que picotear algo azucarado durante todo el día. Cada vez que el niño come algo azucarado o ácido, los dientes ...', 'No es lo mismo tomar un dulce de golpe que picotear algo azucarado durante todo el día. Cada vez que el niño come algo azucarado o ácido, los dientes pasan 30-40 minutos en un ambiente ácido que puede dañar el esmalte. Si come caramelos durante horas, el ataque ácido es casi continuo. Limita los dulces a momentos concretos (postre, merienda) y que siempre vayan seguidos de agua y, si es posible, cepillado.', false, 6),
('2-6', 'alimentacion', 'Alimentos protectores para los dientes de tus hijos', 'No todo lo que comemos daña los dientes: algunos alimentos los protegen activamente. El queso y los lácteos neutralizan los ácidos y aportan calcio. L...', 'No todo lo que comemos daña los dientes: algunos alimentos los protegen activamente. El queso y los lácteos neutralizan los ácidos y aportan calcio. Las verduras crudas como zanahoria o apio actúan como cepillo natural. El agua con flúor ayuda a remineralizar el esmalte. Los frutos secos sin azúcar son ricos en minerales. Incluir estos alimentos en la dieta habitual es una estrategia sencilla para complementar la higiene bucal.', false, 7),
('2-6', 'alimentacion', '¿Cómo gestionar los dulces sin dramas ni restricciones extremas?', 'Prohibir el azúcar totalmente puede generar el efecto contrario: obsesión y excesos cuando hay oportunidad. La clave está en la educación y los hábito...', 'Prohibir el azúcar totalmente puede generar el efecto contrario: obsesión y excesos cuando hay oportunidad. La clave está en la educación y los hábitos. Establece un ''momento del dulce'' predecible (por ejemplo, el postre del fin de semana). Enseña al niño que después hay que beber agua y cepillarse. No uses el dulce como premio o castigo, ya que eso lo convierte en algo especialmente deseable. Un enfoque equilibrado es sostenible y eficaz.', false, 8),
('2-6', 'dentista', 'Revisiones cada 6 meses: ¿de verdad son necesarias?', 'Sí, y especialmente en esta etapa. Entre los 2 y 6 años la boca cambia muchísimo: los dientes de leche están completamente presentes y empiezan a caer...', 'Sí, y especialmente en esta etapa. Entre los 2 y 6 años la boca cambia muchísimo: los dientes de leche están completamente presentes y empiezan a caerse los primeros hacia el final de este periodo. Las revisiones semestrales permiten detectar caries en fase inicial (cuando el tratamiento es simple), aplicar selladores preventivos, valorar la mordida y orientar sobre hábitos. El coste de la prevención siempre es mucho menor que el del tratamiento.', false, 9),
('2-6', 'dentista', 'Los selladores dentales: qué son y para qué sirven', 'Los selladores son un barniz plástico muy fino que el dentista aplica en los surcos de las muelas para protegerlos de las caries. Es un procedimiento ...', 'Los selladores son un barniz plástico muy fino que el dentista aplica en los surcos de las muelas para protegerlos de las caries. Es un procedimiento rápido, indoloro y muy efectivo: reduce el riesgo de caries en zonas posteriores hasta en un 80%. Se aplican habitualmente en los primeros molares definitivos, pero también pueden usarse en molares de leche si el dentista lo considera oportuno. Su aplicación preventiva está muy recomendada.', false, 10),
('2-6', 'dentista', 'El niño que llora en el dentista: estrategias para padres', 'El miedo al dentista en niños pequeños es muy común y totalmente normal. Lo más importante es no forzar ni dramatizar. Prepara al niño en casa con cue...', 'El miedo al dentista en niños pequeños es muy común y totalmente normal. Lo más importante es no forzar ni dramatizar. Prepara al niño en casa con cuentos o juegos de ''dentistas''. Durante la visita, mantén una actitud tranquila porque los niños perciben tu ansiedad. Comunica al dentista de antemano si el niño es miedoso: los odontopediatras tienen técnicas específicas como la ''decir-mostrar-hacer'' que reducen enormemente la ansiedad.', false, 11),
('2-6', 'dentista', 'Radiografías dentales en niños: ¿son seguras?', 'Las radiografías dentales pediátricas son seguras. La dosis de radiación es mínima y, con los delantales de plomo, la exposición es prácticamente insi...', 'Las radiografías dentales pediátricas son seguras. La dosis de radiación es mínima y, con los delantales de plomo, la exposición es prácticamente insignificante. Permiten detectar caries entre los dientes que no son visibles a simple vista, valorar la posición de los dientes definitivos y supervisar el desarrollo de la mandíbula. El dentista solo las solicita cuando son clínicamente necesarias, y los beneficios de la detección temprana superan con creces cualquier riesgo.', false, 12),
('2-6', 'salud', '¿Qué hacer si tu hijo se golpea un diente de leche?', 'Los traumatismos dentales son muy frecuentes a esta edad por caídas y juegos. Si el diente de leche se mueve, cambia de color (grisáceo) o duele al ma...', 'Los traumatismos dentales son muy frecuentes a esta edad por caídas y juegos. Si el diente de leche se mueve, cambia de color (grisáceo) o duele al masticar, acude al dentista en 24-48 horas. Si el diente se fractura y hay un fragmento con bordes cortantes, visita el dentista ese mismo día. Si el diente se cae entero por el golpe (avulsión), a diferencia de los definitivos, no se reimplanta, pero sí hay que revisar que no haya daño en el hueso ni en el diente definitivo.', false, 13),
('2-6', 'salud', 'Bruxismo en niños pequeños: rechinar los dientes al dormir', 'Es muy común que los niños entre 2 y 6 años rechinen los dientes por la noche (bruxismo). En muchos casos es transitorio y no requiere tratamiento, ya...', 'Es muy común que los niños entre 2 y 6 años rechinen los dientes por la noche (bruxismo). En muchos casos es transitorio y no requiere tratamiento, ya que desaparece solo al cambiar la dentición. Sin embargo, si es muy intenso, puede desgastar los dientes de leche. Comenta lo con el dentista en la próxima revisión para que lo evalúe. En general, no es señal de ninguna enfermedad grave; muchas veces está relacionado con el desarrollo mandibular o con el estrés.', false, 14),
('2-6', 'salud', 'Cómo prevenir las caries en los dientes de leche', 'Los dientes de leche son importantes aunque sean temporales: sirven para masticar, hablar correctamente y reservar el espacio para los definitivos. La...', 'Los dientes de leche son importantes aunque sean temporales: sirven para masticar, hablar correctamente y reservar el espacio para los definitivos. La prevención de caries incluye: cepillado con pasta fluorada dos veces al día, reducir el azúcar en la dieta, visitas regulares al dentista y aplicación de flúor o selladores si el dentista lo indica. Una caries en un diente de leche que no se trata puede infectarse y dañar al diente definitivo que está debajo.', false, 15),
('2-6', 'salud', 'Respiración bucal: señal de alarma que afecta a la boca', 'Un niño que respira habitualmente por la boca (especialmente al dormir) puede tener la nariz obstruida por alergias, vegetaciones o un tabique desviad...', 'Un niño que respira habitualmente por la boca (especialmente al dormir) puede tener la nariz obstruida por alergias, vegetaciones o un tabique desviado. La respiración bucal prolongada altera el desarrollo de los maxilares, puede producir paladar ojival (estrecho y alto), favorece las caries (boca seca) y puede generar problemas de maloclusión. Si observas que tu hijo duerme con la boca abierta, ronca o tiene ojeras, consúltalo con el pediatra y el odontopediatra.', false, 16),
('2-6', 'ortodoncia', 'Primera visita al ortodoncista: ¿a qué edad?', 'La Asociación Americana de Ortodoncistas recomienda una primera evaluación ortodóncica a los 7 años, aunque en España muchos especialistas la realizan...', 'La Asociación Americana de Ortodoncistas recomienda una primera evaluación ortodóncica a los 7 años, aunque en España muchos especialistas la realizan incluso antes si hay señales evidentes de problemas. A los 6-7 años ya hay dientes definitivos presentes y es posible evaluar el desarrollo de la mordida, el tamaño de los maxilares y la necesidad de un tratamiento temprano. Esta primera visita es preventiva y no siempre implica iniciar tratamiento.', false, 17),
('2-6', 'ortodoncia', 'Mordida cruzada: qué es y por qué actuar pronto', 'La mordida cruzada ocurre cuando uno o más dientes superiores quedan por dentro de los inferiores al cerrar la boca. Es una de las alteraciones más im...', 'La mordida cruzada ocurre cuando uno o más dientes superiores quedan por dentro de los inferiores al cerrar la boca. Es una de las alteraciones más importantes de tratar en edad temprana porque, si no se corrige, puede provocar asimetría facial y desgaste anormal de los dientes. El tratamiento a los 4-6 años con una placa removible suele ser sencillo, rápido y muy efectivo. Esperar puede complicar enormemente el tratamiento posterior.', false, 18),
('2-6', 'ortodoncia', 'Hábitos que pueden torcer los dientes: cómo gestionarlos', 'La succión prolongada del chupete o del dedo más allá de los 3-4 años puede modificar la posición de los dientes y el desarrollo del paladar, generand...', 'La succión prolongada del chupete o del dedo más allá de los 3-4 años puede modificar la posición de los dientes y el desarrollo del paladar, generando mordida abierta (los dientes frontales no se tocan) o estrechez del paladar. La retirada gradual del chupete antes de los 2-3 años es la mejor prevención. Si el hábito persiste, el dentista puede ayudar con técnicas de modificación de conducta o con aparatos específicos que, aunque suenan intimidantes, son muy tolerables.', false, 19),
('2-6', 'ortodoncia', 'Ortopedia maxilar: expandir el paladar en niños pequeños', 'Si el paladar es estrecho y los dientes no tienen espacio suficiente, el ortodoncista puede recomendar un expansor palatino. A esta edad, el paladar t...', 'Si el paladar es estrecho y los dientes no tienen espacio suficiente, el ortodoncista puede recomendar un expansor palatino. A esta edad, el paladar todavía es cartilaginoso y muy moldeable, lo que hace que el tratamiento sea más eficaz y menos invasivo que en adultos. El expansor es un aparato fijo o removible que amplía gradualmente el paladar. Actuar entre los 4 y 7 años puede evitar extracciones y tratamientos más complejos en la adolescencia.', false, 20),
('6-12', 'lavado', 'Autonomía e independencia: supervisar sin controlar', 'A partir de los 7-8 años los niños pueden empezar a cepillarse solos de forma más autónoma, pero la supervisión sigue siendo necesaria hasta los 10-11...', 'A partir de los 7-8 años los niños pueden empezar a cepillarse solos de forma más autónoma, pero la supervisión sigue siendo necesaria hasta los 10-11 años. Un buen truco es usar pastillas reveladoras de placa (tiñen los restos que el cepillo no quitó) para que el niño vea visualmente dónde falla su técnica. La pasta fluorada a esta edad debe tener entre 1.000 y 1.450 ppm. El tamaño de la pasta es el de un guisante.', true, 1),
('6-12', 'lavado', 'El cepillo eléctrico: ¿vale la pena para los niños?', 'Los estudios muestran que el cepillo eléctrico elimina más placa que el manual cuando se usa correctamente. Para los niños que ya tienen dientes defin...', 'Los estudios muestran que el cepillo eléctrico elimina más placa que el manual cuando se usa correctamente. Para los niños que ya tienen dientes definitivos, puede ser una muy buena opción. Busca modelos con cabezal pequeño, modo suave y temporizador integrado. Sin embargo, un cepillo manual bien usado es igual de efectivo. Lo más importante es que el niño se cepille bien dos minutos, dos veces al día, independientemente del tipo de cepillo.', false, 2),
('6-12', 'lavado', 'Hilo dental y cepillos interdentales: el paso que todos olvidan', 'El 40% de las superficies dentales no se limpian con el cepillo. El hilo dental o los cepillos interdentales son imprescindibles para limpiar entre lo...', 'El 40% de las superficies dentales no se limpian con el cepillo. El hilo dental o los cepillos interdentales son imprescindibles para limpiar entre los dientes, donde se originan muchas caries y enfermedades de las encías. A partir de los 8-9 años, la mayoría de los niños pueden aprender a usarlo solos. Dedica 5 minutos a enseñarles la técnica correcta: en forma de ''C'' alrededor de cada diente, subiéndolo y bajando suavemente.', false, 3),
('6-12', 'lavado', 'Protector bucal para deportes: imprescindible', 'Si tu hijo practica deportes de contacto (fútbol, baloncesto, artes marciales, ciclismo) o deportes con riesgo de caídas, el protector bucal es obliga...', 'Si tu hijo practica deportes de contacto (fútbol, baloncesto, artes marciales, ciclismo) o deportes con riesgo de caídas, el protector bucal es obligatorio. Los traumatismos dentales en esta etapa pueden afectar a los dientes definitivos, con consecuencias para toda la vida. Los protectores termoplásticos (''hierve y muerde'') de farmacia son una opción económica; los personalizados por el dentista ofrecen mayor protección y comodidad. Un golpe a tiempo evitado es un tratamiento ahorrado.', false, 4),
('6-12', 'alimentacion', 'Bebidas deportivas y energéticas: peligrosas para el esmalte', 'Las bebidas deportivas (isotónicas) y las energéticas son extremadamente ácidas y azucaradas, lo que las convierte en uno de los mayores enemigos del ...', 'Las bebidas deportivas (isotónicas) y las energéticas son extremadamente ácidas y azucaradas, lo que las convierte en uno de los mayores enemigos del esmalte dental. A esta edad, los niños pueden acceder a ellas con más facilidad. A menos que el niño haga ejercicio intenso de más de una hora, no necesita bebidas isotónicas: el agua es suficiente. Si las toman ocasionalmente, que sea durante la actividad (no antes ni después) y que luego enjuaguen con agua.', false, 5),
('6-12', 'alimentacion', 'El bocadillo de media mañana: opciones amigables con los dientes', 'El recreo es el momento de mayor consumo de snacks procesados en niños escolares. Propón alternativas que nutran y protejan: palitos de zanahoria o pe...', 'El recreo es el momento de mayor consumo de snacks procesados en niños escolares. Propón alternativas que nutran y protejan: palitos de zanahoria o pepino, trozos de queso, fruta fresca, frutos secos naturales sin sal o bocadillo de pan integral con proteína. Si le das algo dulce, que sea en ese momento concreto y seguido de agua, no repartido a lo largo del recreo. Educar en estos hábitos es una inversión en salud que va mucho más allá de los dientes.', false, 6),
('6-12', 'alimentacion', 'Erosión dental por bebidas ácidas: una epidemia silenciosa', 'La erosión dental es la pérdida de esmalte causada por ácidos, principalmente los de los refrescos, zumos y bebidas energéticas. Los dientes definitiv...', 'La erosión dental es la pérdida de esmalte causada por ácidos, principalmente los de los refrescos, zumos y bebidas energéticas. Los dientes definitivos de los niños tienen el esmalte más fino y son especialmente vulnerables. La erosión no duele al principio, pero los dientes se vuelven más sensibles, amarillentos y con los bordes desgastados. Una vez que el esmalte se pierde, no se recupera. Limita radicalmente las bebidas ácidas y usa pajita cuando las tomen para minimizar el contacto con los dientes.', false, 7),
('6-12', 'alimentacion', 'El papel del calcio y la vitamina D en la salud dental', 'Los dientes definitivos que están terminando de formarse y erupcionando necesitan calcio y vitamina D para mineralizar correctamente. Los lácteos, las...', 'Los dientes definitivos que están terminando de formarse y erupcionando necesitan calcio y vitamina D para mineralizar correctamente. Los lácteos, las verduras de hoja verde, las legumbres y los frutos secos son buenas fuentes de calcio. La vitamina D, necesaria para absorber el calcio, se obtiene principalmente con la exposición solar moderada y, en menor medida, de pescados grasos y huevos. Una dieta equilibrada en esta etapa construye dientes más resistentes y un hueso maxilar más sano.', false, 8),
('6-12', 'dentista', 'La muda de dientes: qué es normal y qué debe revisarse', 'Entre los 6 y 12 años los niños pierden los 20 dientes de leche y les salen los 28 dientes definitivos (sin contar muelas del juicio). Este proceso pu...', 'Entre los 6 y 12 años los niños pierden los 20 dientes de leche y les salen los 28 dientes definitivos (sin contar muelas del juicio). Este proceso puede ser confuso para los padres. Es normal que un diente definitivo empiece a salir antes de que caiga el de leche, generando una doble fila de dientes. Sin embargo, si el diente de leche no cae espontáneamente cuando el definitivo ya está visible, el dentista puede valorar si es necesario extraerlo para evitar problemas de espacio.', false, 9),
('6-12', 'dentista', 'Selladores en molares definitivos: cuándo y por qué', 'Los primeros molares definitivos (las ''muelas de los 6 años'') son los dientes más importantes de la boca y, a la vez, los más propensos a caries por l...', 'Los primeros molares definitivos (las ''muelas de los 6 años'') son los dientes más importantes de la boca y, a la vez, los más propensos a caries por la profundidad de sus surcos. Aplicar selladores dentales en cuanto erupcionen (entre los 6 y 7 años) es una de las medidas preventivas más eficaces disponibles. Es indoloro, rápido y puede durar muchos años. El dentista evaluará en cada revisión si están en buen estado o necesitan renovación.', false, 10),
('6-12', 'dentista', 'Fluorización profesional en la clínica: para quién y por qué', 'La aplicación de flúor en la clínica dental (barniz o gel fluorado) proporciona una concentración de flúor mucho mayor que la pasta casera y protege e...', 'La aplicación de flúor en la clínica dental (barniz o gel fluorado) proporciona una concentración de flúor mucho mayor que la pasta casera y protege el esmalte durante meses. Está especialmente recomendada en niños con alto riesgo de caries: dieta rica en azúcar, higiene deficiente, boca seca, ortodoncia o historial de caries previas. Se aplica en pocos minutos, es indolora y puede marcar una diferencia importante en la salud dental a largo plazo.', false, 11),
('6-12', 'dentista', '¿Qué es la odontopediatría y cuándo pasar al dentista de adultos?', 'La odontopediatría es la especialidad dental enfocada en niños y adolescentes. Los odontopediatras tienen formación específica para tratar a pacientes...', 'La odontopediatría es la especialidad dental enfocada en niños y adolescentes. Los odontopediatras tienen formación específica para tratar a pacientes jóvenes, manejar el miedo y adaptar los tratamientos a cada etapa del desarrollo. En general, la transición al dentista de adultos puede hacerse a partir de los 12-14 años, dependiendo del desarrollo de cada niño y de la relación establecida con su dentista. No hay prisa; lo importante es que el cambio se haga de forma gradual y tranquila.', false, 12),
('6-12', 'salud', 'Gingivitis en niños: cuando las encías sangran al cepillarse', 'El sangrado de las encías al cepillarse no es normal, aunque sea leve. Suele indicar gingivitis, una inflamación causada por la acumulación de placa b...', 'El sangrado de las encías al cepillarse no es normal, aunque sea leve. Suele indicar gingivitis, una inflamación causada por la acumulación de placa bacteriana. En niños, la gingivitis es frecuente y muy tratable: en la mayoría de casos, mejorar la técnica de cepillado y el uso del hilo dental la resuelve en 1-2 semanas. No dejes de cepillar por el sangrado: precisamente hay que cepillar mejor. Si persiste más de dos semanas, visita al dentista.', false, 13),
('6-12', 'salud', 'Traumatismos en dientes definitivos: qué hacer en cada caso', 'A diferencia de los de leche, los dientes definitivos lesionados necesitan atención urgente. Si se fractura un fragmento: guárdalo en leche o suero y ...', 'A diferencia de los de leche, los dientes definitivos lesionados necesitan atención urgente. Si se fractura un fragmento: guárdalo en leche o suero y ve al dentista ese día. Si el diente se cae entero (avulsión): no lo limpies, cógelo por la corona (no por la raíz), colócalo de nuevo en su alvéolo si es posible o consérvalo en leche, y ve al dentista en menos de 30 minutos. La rapidez es clave: un diente reimplantado en las primeras horas puede salvarse.', false, 14),
('6-12', 'salud', 'Halitosis en niños: causas y soluciones', 'El mal aliento (halitosis) en niños suele tener causas simples y tratables. La más frecuente es una higiene bucal insuficiente (placa y restos de alim...', 'El mal aliento (halitosis) en niños suele tener causas simples y tratables. La más frecuente es una higiene bucal insuficiente (placa y restos de alimentos). Otras causas son la boca seca, las caries, la gingivitis, las amígdalas inflamadas o las alergias que provocan respiración bucal. La solución más eficaz es mejorar el cepillado (incluyendo la lengua) y asegurarse de que el niño beba suficiente agua. Si persiste a pesar de buena higiene, consulta al pediatra o al dentista.', false, 15),
('6-12', 'salud', 'La importancia de los dientes de leche que todavía quedan', 'Muchos padres piensan que no merece la pena tratar los dientes de leche ''porque ya se van a caer''. Esto es un error importante. Los dientes de leche m...', 'Muchos padres piensan que no merece la pena tratar los dientes de leche ''porque ya se van a caer''. Esto es un error importante. Los dientes de leche mantienen el espacio para los definitivos: si se pierden por caries o extracción prematura, los dientes vecinos se desplazan y el definitivo no tiene sitio para erupcionar correctamente. Además, una caries profunda en un diente de leche puede infectar el germen del diente definitivo que está justo debajo. Tratar los dientes de leche es siempre la decisión correcta.', false, 16),
('6-12', 'ortodoncia', '¿Es el momento de los brackets? Edad ideal para empezar', 'El tratamiento con brackets fijos suele comenzar entre los 10 y 13 años, cuando ya han erupcionado casi todos los dientes definitivos. Sin embargo, si...', 'El tratamiento con brackets fijos suele comenzar entre los 10 y 13 años, cuando ya han erupcionado casi todos los dientes definitivos. Sin embargo, si hay problemas esqueléticos (maxilares mal posicionados), puede estar indicado un tratamiento ortopédico previo entre los 7 y 9 años. El ortodoncista valorará el caso de forma individualizada. No hay que esperar a que todos los dientes estén colocados para hacer la primera consulta: cuanto antes se planifique, mejor será el resultado.', false, 17),
('6-12', 'ortodoncia', 'Brackets vs. alineadores transparentes en niños', 'Los brackets metálicos siguen siendo el estándar de oro para los tratamientos en niños y adolescentes por su eficacia y bajo coste. Los alineadores tr...', 'Los brackets metálicos siguen siendo el estándar de oro para los tratamientos en niños y adolescentes por su eficacia y bajo coste. Los alineadores transparentes (como Invisalign Teen) son una opción estética atractiva, pero requieren una disciplina alta: deben llevarse 20-22 horas al día. Para niños con buena colaboración y casos de complejidad moderada, pueden funcionar muy bien. El ortodoncista te indicará cuál es la mejor opción según el caso y la motivación del niño.', false, 18),
('6-12', 'ortodoncia', 'Retención: el trabajo que viene después de los brackets', 'Cuando se retiran los brackets, el trabajo no ha terminado. Los dientes tienen ''memoria'' y tienden a volver a su posición original. Por eso, la fase d...', 'Cuando se retiran los brackets, el trabajo no ha terminado. Los dientes tienen ''memoria'' y tienden a volver a su posición original. Por eso, la fase de retención es igual de importante que el tratamiento activo. Normalmente consiste en una retención fija (un hilo pegado detrás de los dientes frontales) y una removible (una plaquita para usar por las noches). El ortodoncista indicará el protocolo más adecuado. Una buena retención garantiza que el resultado dure toda la vida.', false, 19),
('6-12', 'ortodoncia', 'El impacto emocional de la ortodoncia: cómo apoyar a tu hijo', 'Para muchos niños, llevar brackets en la adolescencia puede generar inseguridad o vergüenza. Habla abiertamente con tu hijo sobre el proceso: explícal...', 'Para muchos niños, llevar brackets en la adolescencia puede generar inseguridad o vergüenza. Habla abiertamente con tu hijo sobre el proceso: explícale que es algo temporal y que mejorará su salud y su sonrisa. Involúcralo en la elección de colores de ligaduras, compra alimentos que pueda comer con comodidad y ayúdale a mantener la higiene bucal con ortodoncia (que requiere más esfuerzo). Tu apoyo emocional hace que el tratamiento sea mucho más llevadero. Limpia las encías desde el nacimiento con gasa húmeda Cepilla desde el primer diente con pasta del tamaño de un grano de arroz Evita el biberón nocturno con líquidos dulces Primera visita al dentista antes del año Supervisa siempre el cepillado (2 min, 2 veces al día) Introduce el hilo dental cuando los dientes se tocan Limita el azúcar a momentos concretos del día Revisión dental cada 6 meses Fomenta la autonomía pero sigue supervisando hasta los 10-11 años Protector bucal para deportes de contacto Evita bebidas azucaradas y ácidas Primera consulta de ortodoncia si el dentista lo recomienda', false, 20);
